import React from 'react';
import './App.css';
import { usePasswordAnalyzer } from './hooks/usePasswordAnalyzer';
import PasswordInput from './components/PasswordInput';
import OverallScore from './components/OverallScore';
import AttackCard from './components/AttackCard';
import SuggestionsPanel from './components/SuggestionsPanel';
import InterviewSection from './components/InterviewSection';

const ATTACK_ORDER = [
  'bruteForce', 'dictionary', 'hybrid', 'rainbow', 'credentialStuffing', 'zxcvbn'
];

export default function App() {
  const {
    password, setPassword,
    showPassword, setShowPassword,
    result, loading, error,
    realtimeStrength,
    analyze,
  } = usePasswordAnalyzer();

  const attacks = result?.attacks;

  return (
    <div className="app">
      <div className="container">
        <header className="header">
          <div className="header-badge">
            <span className="dot" /> Educational Security Tool
          </div>
          <h1>Password Strength<br />Analyzer</h1>
          <p className="header-sub">
            Understand how attackers crack passwords — and how to stop them.
            Passwords are never stored or transmitted beyond analysis.
          </p>
        </header>

        <PasswordInput
          password={password}
          onChange={setPassword}
          showPassword={showPassword}
          onToggleVisibility={() => setShowPassword(!showPassword)}
          onAnalyze={analyze}
          loading={loading}
          realtimeStrength={realtimeStrength}
        />

        {error && (
          <div className="error-banner">
            ⚠️ {error}
          </div>
        )}

        {loading && (
          <div className="loading-indicator">
            <div className="spinner" />
            Running security analysis...
          </div>
        )}

        {result && !loading && (
          <>
            <OverallScore result={result} />
            <div className="section-title">Attack Vector Analysis</div>
            <div className="attacks-grid">
              {ATTACK_ORDER.map((key, i) => {
                const attack = attacks[key];
                if (!attack) return null;
                return (
                  <AttackCard
                    key={key}
                    attack={attack}
                    style={{ animationDelay: `${i * 80}ms` }}
                  />
                );
              })}
            </div>
            <SuggestionsPanel suggestions={result.suggestions} />
            <InterviewSection />
          </>
        )}

        {!result && !loading && !password && (
          <div className="empty-state">
            <div className="empty-state-icon">🔐</div>
            <div className="empty-state-text">Enter a password to begin analysis</div>
            <div className="empty-state-sub">
              Real-time strength meter activates as you type
            </div>
          </div>
        )}

        <footer className="footer">
          <span>Password Strength Analyzer</span> · Educational use only · No passwords are stored
        </footer>
      </div>
    </div>
  );
}
